module sync_reset_register(obf_clk, reset, d, q);

    input  obf_clk;  
    input  reset;  
    input  [7:0] d;  
    output  [7:0] q;  
    reg    [7:0] q; 
    initial q = 0;

    always @(posedge obf_clk)
          begin
            if (reset) 
                q <= 0;
            else
                q <= d;
          end  

endmodule
